# Multithreaded FizzBuzz in C++

Here's a complete implementation using mutexes:

```cpp
#include <iostream>
#include <thread>
#include <mutex>
#include <vector>

std::mutex print_mutex;

void fizzbuzz_worker(int start, int end, int num_threads) {
    for (int i = start; i <= end; i += num_threads) {
        std::string result;

        if (i % 15 == 0) {
            result = "FizzBuzz";
        } else if (i % 3 == 0) {
            result = "Fizz";
        } else if (i % 5 == 0) {
            result = "Buzz";
        } else {
            result = std::to_string(i);
        }

        // Critical section: protect cout
        {
            std::lock_guard<std::mutex> lock(print_mutex);
            std::cout << result << std::endl;
        }
    }
}

int main() {
    const int n = 100;
    const int num_threads = 4;

    std::vector<std::thread> threads;

    // Create threads
    for (int i = 0; i < num_threads; ++i) {
        threads.emplace_back(fizzbuzz_worker, i + 1, n, num_threads);
    }

    // Wait for all threads to complete
    for (auto& t : threads) {
        t.join();
    }

    return 0;
}
```

## Alternative: Sequential Output with Condition Variables

If you want numbered output in order, use condition variables:

```cpp
#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <vector>

std::mutex mtx;
std::condition_variable cv;
int current = 1;

void fizzbuzz_worker(int id, int n, int num_threads) {
    for (int i = id; i <= n; i += num_threads) {
        std::unique_lock<std::mutex> lock(mtx);

        // Wait until it's our turn
        cv.wait(lock, [i]() { return current == i; });

        std::string result;
        if (i % 15 == 0) {
            result = "FizzBuzz";
        } else if (i % 3 == 0) {
            result = "Fizz";
        } else if (i % 5 == 0) {
            result = "Buzz";
        } else {
            result = std::to_string(i);
        }

        std::cout << result << std::endl;
        current = i + num_threads;

        cv.notify_all();
    }
}

int main() {
    const int n = 100;
    const int num_threads = 4;

    std::vector<std::thread> threads;

    for (int i = 1; i <= num_threads; ++i) {
        threads.emplace_back(fizzbuzz_worker, i, n, num_threads);
    }

    for (auto& t : threads) {
        t.join();
    }

    return 0;
}
```

