# Longest Increasing Subsequence in C++

Here's a comprehensive solution with multiple approaches:

## 1. **Dynamic Programming Approach (O(n²))**

```cpp
#include <vector>
#include <algorithm>

std::vector<int> longestIncreasingSubsequence(const std::vector<int>& arr) {
    int n = arr.size();
    if (n == 0) return {};

    // dp[i] = length of LIS ending at index i
    std::vector<int> dp(n, 1);
    // parent[i] = previous index in the LIS
    std::vector<int> parent(n, -1);

    // Build the dp array
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[j] < arr[i] && dp[j] + 1 > dp[i]) {
                dp[i] = dp[j] + 1;
                parent[i] = j;
            }
        }
    }

    // Find the index with maximum length
    int maxLength = *std::max_element(dp.begin(), dp.end());
    int maxIndex = std::distance(dp.begin(), 
                                  std::max_element(dp.begin(), dp.end()));

    // Reconstruct the sequence
    std::vector<int> lis;
    int current = maxIndex;
    while (current != -1) {
        lis.push_back(arr[current]);
        current = parent[current];
    }

    std::reverse(lis.begin(), lis.end());
    return lis;
}
```

## 2. **Optimized Binary Search Approach (O(n log n))**

```cpp
#include <vector>
#include <algorithm>

std::vector<int> longestIncreasingSubsequence(const std::vector<int>& arr) {
    int n = arr.size();
    if (n == 0) return {};

    // tail[i] = smallest tail element for LIS of length i+1
    std::vector<int> tail;
    // indices[i] = index in original array of tail[i]
    std::vector<int> indices;
    // parent[i] = index of previous element in LIS
    std::vector<int> parent(n, -1);

    for (int i = 0; i < n; i++) {
        auto it = std::lower_bound(tail.begin(), tail.end(), arr[i]);
        int pos = std::distance(tail.begin(), it);

        if (pos > 0) {
            parent[i] = indices[pos - 1];
        }

        if (pos == tail.size()) {
            tail.push_back(arr[i]);
            indices.push_back(i);
        } else {
            tail[pos] = arr[i];
            indices[pos] = i;
        }
    }

    // Reconstruct the sequence
    std::vector<int> lis;
    if (!indices.empty()) {
        int current = indices.back();
        while (current != -1) {
            lis.push_back(arr[current]);
            current = parent[current];
        }
        std::reverse(lis.begin(), lis.end());
    }

    return lis;
}
```

## 3. **Simple Length-Only Version (O(n²))**

```cpp
int longestIncreasingLength(const std::vector<int>& arr) {
    int n = arr.size();
    if (n == 0) return 0;

    std::vector<int> dp(n, 1);

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[j] < arr[i]) {
                dp[i] = std::max(dp[i], dp[j] + 1);
            }
        }
    }

    return *std::max_element(dp.begin(), dp.end());
}
```

## Usage Examples

```cpp
#include <iostream>

int main() {
    std::vector<int> arr = {10, 9, 2, 5, 3, 7, 101, 18};

    // Get the LIS
    std::vector<int> result = longestIncreasingSubsequence(arr);

    std::cout << "Longest Increasing Subsequence: ";
    for (int num : result) {
        std::cout << num << " ";
    }
    std::cout << "\nLength: " << result.size() << std::endl;

    // Output: Longest Increasing Subsequence: 2 3 7 101 
    // Length: 4

    return 0;
}
```

## Comparison

| Approach | Time | Space | Notes |
|----------|------|-------|-------|
| DP O(n²) | O(n²) | O(n) | Simple, good for small inputs |
| Binary Search | O(n log n) | O(n) | **Best overall**, scalable |
| Length only | O(n²) | O(n) | Minimal overhead |

**Recommendation**: Use the **Binary Search approach** for production code as it offers optimal time complexity with reasonable implementation complexity.

# Triangle Area Algorithm (Heron's Formula)

## Algorithm Overview
Uses **Heron's Formula** to calculate the area from three sides.

## Pseudocode

```
ALGORITHM CalculateTriangleArea(side1, side2, side3)

    // Step 1: Validate that sides form a valid triangle
    IF (side1 + side2 <= side3) OR 
       (side2 + side3 <= side1) OR 
       (side1 + side3 <= side2) THEN
        RETURN "Invalid triangle"
    END IF

    // Step 2: Calculate semi-perimeter
    s = (side1 + side2 + side3) / 2

    // Step 3: Apply Heron's Formula
    area = √(s × (s - side1) × (s - side2) × (s - side3))

    // Step 4: Return result
    RETURN area

END ALGORITHM
```

## Implementation Examples

### Python
```python
import math

def calculate_triangle_area(a, b, c):
    """
    Calculate triangle area using Heron's Formula
    Args: a, b, c (float): Three sides of the triangle
    Returns: float or str: Area or error message
    """
    # Validate triangle inequality theorem
    if a + b <= c or b + c <= a or a + c <= b:
        return "Invalid triangle: sides don't form a valid triangle"

    # Calculate semi-perimeter
    s = (a + b + c) / 2

    # Apply Heron's Formula
    area = math.sqrt(s * (s - a) * (s - b) * (s - c))

    return area

# Test cases
print(calculate_triangle_area(3, 4, 5))      # Output: 6.0
print(calculate_triangle_area(5, 5, 5))      # Output: 10.83 (equilateral)
print(calculate_triangle_area(1, 2, 10))     # Output: Invalid triangle
```

