/* styles.css */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --primary-color: #8B4513;
    --secondary-color: #D2691E;
    --accent-color: #FF6B6B;
    --text-dark: #333;
    --text-light: #666;
    --bg-light: #f9f7f4;
    --white: #ffffff;
    --shadow: 0 5px 20px rgba(0,0,0,0.1);
}

html {
    scroll-behavior: smooth;
}

body {
