    position: relative;
    transition: color 0.3s;
}

.cart-btn:hover, .user-menu-toggle:hover {
    color: var(--secondary-color);
}

.cart-count {
    position: absolute;
    top: -5px;
    right: -5px;
    background: var(--accent-color);
    color: var(--white);
    border-radius: 50%;
    width: 20px;
    height: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.8rem;
}

/* Buttons */
.btn {
