# customer_service_ai.py
import os
from anthropic import Anthropic
from datetime import datetime
from typing import Optional

class AICustomerServiceAgent:
    """AI-powered customer service system using Claude API with conversation memory"""

    def __init__(self, api_key: Optional[str] = None):
        self.client = Anthropic()
        self.conversation_history = []
        self.customer_context = {}

    def set_customer_context(self, customer_id: str, name: str, 
                            account_type: str, purchase_history: list):
        """Store customer information for personalized service"""
        self.customer_context = {
            "customer_id": customer_id,
            "name": name,
            "account_type": account_type,
            "purchase_history": purchase_history,
            "session_start": datetime.now().isoformat()
        }

    def get_system_prompt(self) -> str:
        """Generate dynamic system prompt with customer context"""
        context_str = ""
        if self.customer_context:
            context_str = f"""
Customer Information:
- Name: {self.customer_context['name']}
- Account Type: {self.customer_context['account_type']}
- Recent Purchases: {', '.join(self.customer_context['purchase_history'][-3:])}
"""

        return f"""You are an expert customer service representative for TechStore, a leading electronics retailer. 
Your role is to:
1. Address customer issues with empathy and professionalism
2. Provide product information and recommendations
3. Process returns, refunds, and exchanges
4. Troubleshoot technical problems
5. Offer solutions that prioritize customer satisfaction

{context_str}

Guidelines:
- Be concise but thorough in your responses
- Offer proactive solutions
- Escalate to human support if needed (clearly state when)
- Use the customer's name when appropriate
- Maintain a friendly, professional tone"""

    def chat(self, user_message: str) -> str:
        """Send a message and get AI response with conversation history"""
        # Add user message to history
        self.conversation_history.append({
            "role": "user",
            "content": user_message
        })

        # Get response from Claude
        response = self.client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1024,
            system=self.get_system_prompt(),
            messages=self.conversation_history
        )

        assistant_message = response.content[0].text

        # Add assistant response to history
        self.conversation_history.append({
            "role": "assistant",
            "content": assistant_message
        })

        return assistant_message

    def get_conversation_summary(self) -> str:
        """Generate a summary of the conversation for handoff to human agent"""
        if len(self.conversation_history) < 2:
            return "No significant conversation history."

        summary_prompt = f"""Provide a brief summary of this customer service conversation in 3-4 sentences.
Include: customer issue, attempted solutions, and current status.

Conversation:
{self._format_history_for_summary()}"""

        response = self.client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=300,
            messages=[{"role": "user", "content": summary_prompt}]
        )

        return response.content[0].text

    def _format_history_for_summary(self) -> str:
        """Format conversation history for display"""
        formatted = []
        for msg in self.conversation_history:
            role = "Customer" if msg["role"] == "user" else "Support"
            formatted.append(f"{role}: {msg['content']}")
        return "\n".join(formatted)

    def clear_conversation(self):
        """Reset conversation history for a new customer"""
        self.conversation_history = []
        self.customer_context = {}


