```python
# api_service.py
from flask import Flask, request, jsonify
from flask_cors import CORS
from customer_service_ai import AICustomerServiceAgent
import json

app = Flask(__name__)
CORS(app)

# Store active customer service sessions
active_sessions = {}

@app.route('/api/start-session', methods=['POST'])
def start_session():
    """Initialize a new customer service session"""
    data = request.json

    session_id = data.get('session_id')
    customer_info = data.get('customer_info', {})

    agent = AICustomerServiceAgent()
    agent.set_customer_context(
        customer_id=customer_info.get('id', 'UNKNOWN'),
        name=customer_info.get('name', 'Guest'),
        account_type=customer_info.get('account_type', 'Standard'),
        purchase_history=customer_info.get('purchases', [])
    )

    active_sessions[session_id] = agent

    return jsonify({
        "success": True,
        "session_id": session_id,
        "message": f"Hello {customer_info.get('name', 'customer')}! How can we help you today?"
    })

@app.route('/api/message', methods=['POST'])
def send_message():
    """Send a customer message and get AI response"""
    data = request.json
    session_id = data.get('session_id')
    message = data.get('message')

    if session_id not in active_sessions:
        return jsonify({"error": "Invalid session"}), 404

    agent = active_sessions[session_id]
    response = agent.chat(message)

    return jsonify({
        "success": True,
        "response": response
    })

@app.route('/api/summary', methods=['GET'])
def get_summary():
    """Get conversation summary"""
    session_id = request.args.get('session_id')

    if session_id not in active_sessions:
        return jsonify({"error": "Invalid session"}), 404

    agent = active_sessions[session_id]
    summary = agent.get_conversation_summary()

    return jsonify({
        "success": True,
        "summary": summary
    })

@app.route('/api/end-session', methods=['POST'])
def end_session():
    """End a customer service session"""
    data = request.json
    session_id = data.get('session_id')

    if session_id in active_sessions:
        del active_sessions[session_id]

    return jsonify({"success": True})

if __name__ == "__main__":
    app.run(debug=True, port=5000)
```

