                account_type: 'Premium',
                purchases: ['Laptop - 2024', 'USB Hub - 2024', 'Monitor - 2023']
            };

            try {
                const response = await fetch(`${API_BASE}/start-session`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        session_id: sessionId,
                        customer_info: customerInfo
                    })
                });

                const data = await response.json();

                // Display customer info
                document.getElementById('customerName').textContent = customerInfo.name;
                document.getElementById('accountType').textContent = customerInfo.account_type;
                document.getElementById('customerInfo').style.display = 'flex';

                // Add greeting message
                addMessage('support', data.message);
            } catch (error) {
                console.error('Error initializing session:', error);
                addMessage('system', 'Connection error. Please refresh the page.');
            }
        }

        async function sendMessage() {
            const input = document.getElementById('messageInput');
            const message = input.value.trim();

            if (!message || isWaitingForResponse) return;

            // Add customer message to chat
            addMessage('customer', message);
            input.value = '';

            // Show typing indicator
            showTypingIndicator();
            isWaitingForResponse = true;

            try {
                const response = await fetch(`${API_BASE}/message`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        session_id: sessionId,
                        message: message
                    })
                });

                const data = await response.json();
                removeTypingIndicator();

                if (data.success) {
                    addMessage('support', data.response);
                } else {
                    addMessage('system', 'Error getting response. Please try again.');
                }
            } catch (error) {
                console.error('Error sending message:', error);
                removeTypingIndicator();
                addMessage('system', 'Network error. Please try again.');
            } finally {
                isWaitingForResponse = false;
                document.getElementById('messageInput').focus();
            }
        }

        function addMessage(sender, text) {
            const chatContainer = document.getElementById('chatContainer');
            const messageDiv = document.createElement('div');
            messageDiv.className = `message ${sender}`;
            messageDiv.innerHTML = `<div class="message-content">${escapeHtml(text)}</div>`;
            chatContainer.appendChild(messageDiv);
            chatContainer.scrollTop = chatContainer.scrollHeight;
        }

        function showTypingIndicator() {
            const chatContainer = document.getElementById('chatContainer');
            const typingDiv = document.createElement('div');
            typingDiv.id = 'typingIndicator';
            typingDiv.className = 'message support';
            typingDiv.innerHTML = `
                <div class="typing-indicator">
                    <div class="typing-dot"></div>
                    <div class="typing-dot"></div>
                    <div class="typing-dot"></div>
                </div>
            `;
            chatContainer.appendChild(typingDiv);
            chatContainer.scrollTop = chatContainer.scrollHeight;
        }

        function removeTypingIndicator() {
            const indicator = document.getElementById('typingIndicator');
            if (indicator) indicator.remove();
        }

        function handleKeyPress(event) {
            if (event.key === 'Enter' && !event.shiftKey) {
                event.preventDefault();
                sendMessage();
            }
        }

        function quickAction(action) {
            const actions = {
                'return': 'I want to return my recent purchase',
                'technical': 'I need help with a technical issue',
                'shipping': 'Can you help me with shipping information?'
            };
            document.getElementById('messageInput').value = actions[action] || '';
            document.getElementById('messageInput').focus();
        }

        function escapeHtml(text) {
            const map = {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;',
                "'": '&#039;'
            };
            return text.replace(/[&<>"']/g, m => map[m]);
        }

        // Initialize on page load
        document.addEventListener('DOMContentLoaded', initializeSession);
    </script>
</body>
</html>
```

## 4. Key Features

✅ **Multi-turn Conversations** - Maintains context across messages  
✅ **Customer Personalization** - Uses customer data for tailored responses  
✅ **Conversation Memory** - Remembers history within a session  
✅ **Session Management** - Tracks multiple customer sessions  
✅ **Sentiment Analysis** - Evaluates customer satisfaction  
✅ **Escalation Support** - Identifies when human help is needed  
✅ **Web Interface** - Clean, responsive chat UI  
✅ **Summary Generation** - Creates handoff notes for human agents  

This solution provides 24/7 customer support while reducing response times and improving satisfaction!

