# Bogosort in C++

Here's a complete implementation of bogosort (also known as "stupid sort"), which randomly shuffles the array until it's sorted:

```cpp
#include <iostream>
#include <algorithm>
#include <cstdlib>
#include <ctime>
#include <vector>

using namespace std;

// Function to check if array is sorted
bool isSorted(vector<int>& arr) {
    for (int i = 0; i < arr.size() - 1; i++) {
        if (arr[i] > arr[i + 1]) {
            return false;
        }
    }
    return true;
}

// Bogosort implementation
void bogoSort(vector<int>& arr) {
    while (!isSorted(arr)) {
        random_shuffle(arr.begin(), arr.end());
    }
}

// Utility function to print array
void printArray(vector<int>& arr) {
    for (int num : arr) {
        cout << num << " ";
    }
    cout << endl;
}

// Main function
int main() {
    srand(time(0)); // Seed random number generator

    vector<int> arr = {5, 2, 8, 1, 9};

    cout << "Original array: ";
    printArray(arr);

    cout << "Sorting..." << endl;
    bogoSort(arr);

    cout << "Sorted array: ";
    printArray(arr);

    return 0;
}
```

## Modern C++ Version (C++17+)

For a more modern approach using `std::shuffle`:

```cpp
#include <iostream>
#include <algorithm>
#include <random>
#include <vector>

using namespace std;

bool isSorted(const vector<int>& arr) {
    return is_sorted(arr.begin(), arr.end());
}

void bogoSort(vector<int>& arr) {
    random_device rd;
    mt19937 g(rd());

    while (!isSorted(arr)) {
        shuffle(arr.begin(), arr.end(), g);
    }
}

void printArray(const vector<int>& arr) {
    for (int num : arr) {
        cout << num << " ";
    }
    cout << endl;
}

int main() {
    vector<int> arr = {5, 2, 8, 1, 9};

    cout << "Original array: ";
    printArray(arr);

    cout << "Sorting..." << endl;
    bogoSort(arr);

    cout << "Sorted array: ";
    printArray(arr);

    return 0;
}
```

## Output Example:
```
Original array: 5 2 8 1 9 
Sorting...
Sorted array: 1 2 5 8 9
```

## ⚠️ Important Notes:

- **DO NOT use in production!** Bogosort has a worst-case time complexity of **O(∞)** and average case of **O(n·n!)**
- It's extremely inefficient even for small arrays (try it with more than 10 elements and it might take forever)
- It's mainly used for educational purposes to demonstrate what NOT to do
- The algorithm is also called "stupid sort," "slow sort," or "random sort"

