class ModelLoader(context: Context) {
    private var interpreter: Interpreter? = null

    fun loadModel(assetPath: String) {
        try {
            val modelBuffer = loadModelFile(context, assetPath)
            interpreter = Interpreter(modelBuffer)
        } catch (e: Exception) {
            Log.e("ModelLoader", "Failed to load model", e)
        }
    }

    private fun loadModelFile(
        context: Context, 
        modelPath: String
    ): MappedByteBuffer {
        val assetManager = context.assets
        val fileDescriptor = assetManager.openFd(modelPath)

        return FileInputStream(fileDescriptor.fileDescriptor)
            .channel
            .map(
                FileChannel.MapMode.READ_ONLY,
                fileDescriptor.startOffset,
                fileDescriptor.declaredLength
            )
    }
}
