## 4. Input Preprocessing

### Image Preprocessing
```kotlin
class ImagePreprocessor {

    fun preprocessImage(bitmap: Bitmap, inputSize: Int): ByteBuffer {
        val buffer = ByteBuffer.allocateDirect(
            4 * inputSize * inputSize * 3
        )
        buffer.order(ByteOrder.nativeOrder())

        // Resize image
        val resized = Bitmap.createScaledBitmap(
            bitmap, 
            inputSize, 
            inputSize, 
            true
        )

        val intValues = IntArray(inputSize * inputSize)
        resized.getPixels(
            intValues, 0, inputSize, 
            0, 0, inputSize, inputSize
        )

        // Normalize pixel values
        var pixel = 0
        for (i in intValues.indices) {
            val value = intValues[i]

            // Extract RGB channels
            buffer.putFloat(((value shr 16) and 0xFF) / 255.0f)  // R
            buffer.putFloat(((value shr 8) and 0xFF) / 255.0f)   // G
            buffer.putFloat((value and 0xFF) / 255.0f)            // B
        }

        return buffer
    }
}
```

