## 6. Output Postprocessing

### Classification Results
```kotlin
class ClassificationProcessor(private val labels: List<String>) {

    data class Prediction(
        val label: String,
        val confidence: Float
    )

    fun processOutput(
        output: FloatArray, 
        topK: Int = 5
    ): List<Prediction> {
        return output
            .mapIndexed { index, confidence -> 
                Pair(labels[index], confidence) 
            }
            .sortedByDescending { it.second }
            .take(topK)
            .map { (label, confidence) ->
                Prediction(label, confidence)
            }
    }
}
