```kotlin
class MLActivity : AppCompatActivity() {

    private lateinit var mlModel: MLModel
    private lateinit var imagePreprocessor: ImagePreprocessor
    private lateinit var classificationProcessor: ClassificationProcessor

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_ml)

        initializeModel()
        setupUI()
    }

    private fun initializeModel() {
        mlModel = MLModel(this)
        imagePreprocessor = ImagePreprocessor()
        classificationProcessor = ClassificationProcessor(loadLabels())
    }

    private fun setupUI() {
        val imageView = findViewById<ImageView>(R.id.imageView)
        val resultText = findViewById<TextView>(R.id.resultText)

        imageView.setOnClickListener {
            val bitmap = BitmapFactory.decodeResource(
                resources, 
                R.drawable.sample_image
            )
            performInference(bitmap, resultText)
        }
    }

    private fun performInference(
        bitmap: Bitmap, 
        resultView: TextView
    ) {
        Thread {
            try {
                // Preprocess
                val input = imagePreprocessor.preprocessImage(bitmap, 224)

                // Infer
                val output = mlModel.predict(input)

                // Postprocess
                val predictions = classificationProcessor.processOutput(output)

                // Update UI
                runOnUiThread {
                    resultView.text = predictions
                        .joinToString("\n") { 
                            "${it.label}: ${it.confidence}" 
                        }
                }
            } catch (e: Exception) {
                Log.e("MLActivity", "Inference failed", e)
            }
        }.start()
    }

    private fun loadLabels(): List<String> {
        return assets.open("labels.txt").bufferedReader().useLines {
            it.toList()
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        mlModel.close()
    }
}
